import Page from 'components/Page';
import { Consumer } from "../components/Context";
import { DisplayWidget } from 'components/Widget';
import React from 'react';
import SourceLink from 'components/SourceLink';
import { Pie, Doughnut, Bar, Polar, HorizontalBar } from 'react-chartjs-2';
import { getColor } from 'utils/colors';
import { randomNum } from 'utils/demos';
import conf from "../api/config";
import { findDashboardMeta } from "../api/api";
import AsyncStorage from '@callstack/async-storage';
import {
  Card,
  CardBody,
  CardHeader,
  Col,
  Row,
  Alert,
} from 'reactstrap';

class DashboardPage extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      visualizations : [],
      revexp:[],
      toptentrucks:[],
      topfiveexp:[],
      topfivetruckbyload:[],
      topfivetruckbymileage:[],
      xtoken:'',
    };
    AsyncStorage.getItem(conf.secret)
    .then((results) => {
      if( results !== null )
      {
        let obje_results = JSON.parse(results);
        this.setState({
          ...this.state,
          xtoken : obje_results.user.token,
        });
        findDashboardMeta(obje_results.user.token).then((response) => {
            this.setState({
                ...this.state,
                visualizations:response.data,
                // toptentrucks:response.data.top_ten,
                // topfiveexp:response.data.top_five_exp,
                // topfivetruckbyload:response.data.top_five_loads,
                // topfivetruckbymileage:response.data.top_five_mileage,
                // revexp:response.data.revexp,
            });
            console.log('months data', this.state.revexp);
        }).catch((respError) => {
          console.log('respError', respError);
        });
      }
    })
    .catch((error) => {
      console.log('storage error', error);
    });
  }

  genRevenueExpenseData = (input, moreData = {}, moreData2 = {}) => {
    const MONTHS = this.extractSetMonthKeys(input);
    return {
      labels: MONTHS,
      datasets: [
        {
          label: 'Cash Inflow(KES1000)',
          backgroundColor: getColor('primary'),
          borderColor: getColor('primary'),
          borderWidth: 1,
          data: this.extractSetExpValues(input),
          ...moreData,
        },
        {
          label: 'Cash Outflow(KES1000)',
          backgroundColor: getColor('secondary'),
          borderColor: getColor('secondary'),
          borderWidth: 1,
          data: this.extractSetRevValues(input),
          ...moreData2,
        },
      ],
    };
  };
  extractSetMonthKeys = (dataset) => {
    let keys = [];
    dataset.forEach( function(x){
      let mkey = Object.keys(x)[0];
      keys.push(mkey.split('~')[1]);
    });
    return keys;
  }
  extractSetRevValues = (dataset) => {
    let keys = [];
    dataset.forEach( function(x){
      let mkey = Object.values(x)[0];
      keys.push(mkey.split('~')[0]);
    });
    return keys;
  }
  extractSetExpValues = (dataset) => {
    let keys = [];
    dataset.forEach( function(x){
      let mkey = Object.values(x)[0];
      keys.push(mkey.split('~')[1]);
    });
    return keys;
  }
  extractSetKeys = (dataset) => {
    let keys = [];
    dataset.forEach( function(x){
      keys.push(Object.keys(x)[0])
    });
    return keys;
  }
  extractSetValues = (dataset) => {
    let values = [];
    dataset.forEach( function(x){
      values.push(Object.values(x)[0])
    });
    return values;
  }
  genHoriBarData = (input) => {
    return { data: {
          labels: this.extractSetKeys(input),
          datasets: [
            {
              label: 'Fees in KES',
              backgroundColor: getColor('danger'),
              borderColor: getColor('danger'),
              borderWidth: 1,
              hoverBackgroundColor: getColor('danger'),
              hoverBorderColor: getColor('danger'),
              data: this.extractSetValues(input),
            }
          ]
        },
        options: {
          scales: {
            xAxes: [{
                gridLines: {
                    color: "rgba(0, 0, 0, 0)",
                }
            }],
            yAxes: [{
                gridLines: {
                    color: "rgba(0, 0, 0, 0)",
                }   
            }]
          }
        }
      };
  };
  
  genTopExpensePieData = (input) => {
    let set_lables = this.extractSetKeys(input);
    return {
      datasets: [
        {
          data: this.extractSetValues(input),
          backgroundColor: [
            getColor('primary'),
            getColor('secondary'),
            getColor('success'),
            getColor('info'),
            getColor('danger'),
          ],
          label: set_lables[0],
        },
      ],
      labels: set_lables,
    };
  };
  
  genLoadsByTruckPieData = (input) => {
    let set_lables = this.extractSetKeys(input);
    return {
      datasets: [
        {
          data: this.extractSetValues(input).slice(0, 5),
          backgroundColor: [
            getColor('primary'),
            getColor('secondary'),
            getColor('success'),
            getColor('info'),
            getColor('danger'),
          ],
          label: set_lables[0],
        },
      ],
      labels: set_lables.slice(0, 5),
    };
  };
  
  genTruckMileagePieData = (input) => {
    let set_lables = this.extractSetKeys(input);
    return {
      datasets: [
        {
          data: this.extractSetValues(input).slice(0, 5),
          backgroundColor: [
            getColor('primary'),
            getColor('secondary'),
            getColor('success'),
            getColor('info'),
            getColor('danger'),
          ],
          label: set_lables[0],
        },
      ],
      labels: set_lables.slice(0, 5),
    };
  };
  componentDidMount() {
    window.scrollTo(0, 0);
  }

  render() {
    const primaryColor = getColor('primary');
    const secondaryColor = getColor('secondary');
    return (
      <Consumer>
        {context => (
          <Page
            className="DashboardPage"
            title={process.env.REACT_APP_NAME}
            breadcrumbs={[{ name: 'Dashboard', active: true }]}
          >
            
            <Row>
              <Col lg={12} md={12} sm={12} xs={12}>
                {parseInt(context.state.user.has_setup) === 0 && (
                  <Alert color="danger">You have not completed your <b>{process.env.REACT_APP_NAME}</b> system setup. 
                    <SourceLink target="_self" href="/co/setup">
                    {" "} Complete setup
                    </SourceLink>
                  </Alert>
                )}
              </Col>
            </Row>

            <Row>
              <Col className="small-padding" xl={3} md={6} sm={12} xs={12}>
                <DisplayWidget
                  title="Monthily Fees"
                  number={this.state.visualizations.cont}
                  color="secondary"
                />
              </Col>
              <Col className="small-padding" xl={3} md={6} sm={12} xs={12}>
                <DisplayWidget
                  title="Students"
                  number={this.state.visualizations.me}
                  color="danger"
                />
              </Col>
              <Col className="small-padding" xl={3} md={6} sm={12} xs={12}>
                <DisplayWidget
                  title="Monthily Expenses"
                  number={this.state.visualizations.loan}
                  color="primary"
                />
              </Col>
              <Col className="small-padding" xl={3} md={6} sm={12} xs={12}>
                <DisplayWidget
                  title="Teachers"
                  number={this.state.visualizations.def}
                  color="success"
                />
              </Col>
            </Row>
            <br></br>
            <Row>
              <Col xl={6} lg={12} md={12}>
                <Card>
                  <CardHeader className="text-primary">Top Fees Balances </CardHeader>
                  <CardBody>
                    <HorizontalBar data={this.genHoriBarData(this.state.toptentrucks).data} options={this.genHoriBarData(this.state.toptentrucks).options} />
                  </CardBody>
                </Card>
              </Col>
              <Col xl={6} lg={12} md={12}>
                <Card>
                  <CardHeader className="text-secondary">Cash Inflow VS Outflow (Last 6months)</CardHeader>
                  <CardBody>
                    <Bar data={this.genRevenueExpenseData(this.state.revexp, { type: 'line', fill: false })} />
                  </CardBody>
                </Card>
              </Col>
            </Row>
                               
          </Page>
          )}
      </Consumer>
    );
  }
}
export default DashboardPage;
